#include<bits/stdc++.h>
using namespace std;

int x[1001];

int main()
{
	int m,n;
	scanf("%d%d",&m,&n);
	for(int i=0;i<n;i++)
	{
		scanf("%d",&x[i]); 
	}
	sort(x,x+n);
	int cnt=0;  
	int sum=0;  
	for (int i=0;i<n;i++)
	{
    	if (sum+x[i]<=m)
		{
        	sum+=x[i];
        	cnt++;
    	} 
		else 
		{
       		break; 
    	}
	}
	printf("%d",cnt);
	return 0;
}
